-- ============================================================
-- Custom20 Module - World Database Install
-- Version: 1.1
-- Description: Adds custom level 20 mounts for all races,
--              including mount spells, vendor NPCs, quest
--              relations, creature spawns, and model data.
-- Apply to: World DB
-- ============================================================

-- ------------------------------------------------------------
-- Spell Templates (custom level 20 mount spells, IDs 34000-34015)
-- ------------------------------------------------------------

-- Human: Honor Steed (34000), Harvest Steed (34001)
DELETE FROM `spell_template` WHERE `Id` IN (34000, 34001);

-- Undead: White Skeletal Horse (34002), Scarlet Skeletal Horse (34003)
DELETE FROM `spell_template` WHERE `Id` IN (34002, 34003);

-- Night Elf: White Sabertooth (34004), Black Sabertooth (34005)
-- Gnome: Emerlight Mechanostrider (34006), Whiteflare Mechanostrider (34007)
-- Dwarf: Coal Ram (34008), Glacier Ram (34009)
-- Troll: Bwon'Scara Raptor (34010), Jin'Roka Raptor (34011)
-- Orc: Frostfang Wolf (34012), Embermane Wolf (34013)
-- Tauren: Mosshide Kodo (34014), Skyhide Kodo (34015)
DELETE FROM `spell_template` WHERE `Id` IN (34004, 34005, 34006, 34007, 34008, 34009, 34010, 34011, 34012, 34013, 34014, 34015);

-- ------------------------------------------------------------
-- Creature Model Info (custom mount display models)
-- ------------------------------------------------------------

DELETE FROM `creature_model_info` WHERE `modelid` IN (18000, 18001);

-- ------------------------------------------------------------
-- Creature Templates (mount vendor NPCs)
-- Alliance: Human, Night Elf, Dwarf, Gnome vendors
-- Horde: Orc, Undead, Tauren, Troll vendors
-- ------------------------------------------------------------

DELETE FROM `creature_template` WHERE `Entry` IN (240, 1139, 1261, 1265, 1268, 1515, 1745, 2930, 3054, 3338, 3428, 3431, 3432, 3690, 4730, 5613, 5782, 6749, 7937, 7954, 9979, 10054, 12481, 14392);

-- ------------------------------------------------------------
-- Creature Quest Relations (mount vendor quest turn-ins)
-- Quests 9700-9723
-- ------------------------------------------------------------

DELETE FROM `creature_involvedrelation` WHERE `quest` BETWEEN 9700 AND 9723;

-- ------------------------------------------------------------
-- Creature Spawns (mount vendor NPC world positions)
-- GUIDs 9000453-9000471
-- ------------------------------------------------------------

DELETE FROM `creature` WHERE `guid` IN (9000453, 9000454, 9000455, 9000456, 9000457, 9000458, 9000459, 9000461, 9000462, 9000463, 9000464, 9000466, 9000468, 9000469, 9000470, 9000471);
